class Solution {
    // Function to check if the array is sorted
    isSorted(arr, n) {
        for (let i = 0; i < n - 1; i++) {
            if (arr[i] > arr[i + 1]) 
                return false;
        }
        return true;
    }
}

// Driver code
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let i = 0;
let n;
let arr;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        let obj = new Solution();
        let ans = obj.isSorted(arr, n);
        if (ans) console.log("True");
        else console.log("False");
        readline.close();
    }
    i++;
});
